SELECT WMS_ArticoliCosmos_RunMisti_step1.[Sell-to Customer No_], WMS_ArticoliCosmos_RunMisti_step1.[Bill-to Customer No_], WMS_ArticoliCosmos_RunMisti_step1.[Bill-to Name], WMS_ArticoliCosmos_RunMisti_step1.[Document No_], WMS_ArticoliCosmos_RunMisti_step1.[Line No_], [Registered Whse_ Activity Line].[Item No_], [Registered Whse_ Activity Line].[Constant Variable Code], [Unique Identifier Pst_ Docnts].Code, Val([item identifier.No_ of Pairs]) AS qty, IIf(Left$([item identifier.code],8)="F2400116" Or Left$([item identifier.code],8)="F2400120","FIRST","SECOND") AS qualityLevel
FROM (([Item Identifier] INNER JOIN ([Unique Identifier Pst_ Docnts] INNER JOIN [Registered Whse_ Activity Line] ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Registered Whse_ Activity Line].[Line No_]) AND ([Unique Identifier Pst_ Docnts].No_ = [Registered Whse_ Activity Line].No_)) ON [Item Identifier].Code = [Unique Identifier Pst_ Docnts].Code) INNER JOIN [Registered Whse_ Activity Hdr_] ON [Registered Whse_ Activity Line].No_ = [Registered Whse_ Activity Hdr_].No_) INNER JOIN WMS_ArticoliCosmos_RunMisti_step1 ON ([Registered Whse_ Activity Line].[Link To Source Line No_] = WMS_ArticoliCosmos_RunMisti_step1.[Line No_]) AND ([Registered Whse_ Activity Line].[Link To Source No_] = WMS_ArticoliCosmos_RunMisti_step1.[Document No_])
WHERE ((([Registered Whse_ Activity Line].[Item No_])="NP0A88XV") AND (([Registered Whse_ Activity Hdr_].[Whse_ Phase Code])="OUT.PRE") AND (([Registered Whse_ Activity Line].[Action Type])=2));

